// // This comment suggests that the counter decrements on the rising edge of the clock when the enable signal is high.
module binary_counter(CLK,RST,EN,COUNT);
input CLK,RST,EN;
output [3:0] COUNT;
reg [3:0] COUNT;

always@(posedge CLK or posedge RST) begin
	if (RST)
		COUNT <= 0;
	else if (EN)
		COUNT <= COUNT + 1;
	else
		COUNT <= COUNT;
end

endmodule
